import express from 'express';
import path from 'path';
import fs from 'fs';
import { createServer as createViteServer } from 'vite';
import { db } from './src/server/db.js';
import { parseResumeAndScore, searchCandidatesAi } from './src/server/gemini.js';
import { Candidate, Vacancy } from './src/types.js';

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Ensure curriculos directory exists
  const RESUMES_DIR = path.join(process.cwd(), 'curriculos');
  if (!fs.existsSync(RESUMES_DIR)) {
    fs.mkdirSync(RESUMES_DIR, { recursive: true });
  }

  // Configure JSON parser with larger limits for base64 resumes
  app.use(express.json({ limit: '50mb' }));
  app.use(express.urlencoded({ extended: true, limit: '50mb' }));

  // Helper middleware for admin authentication
  const requireAdmin = (req: express.Request, res: express.Response, next: express.NextFunction) => {
    const authHeader = req.headers.authorization;
    if (authHeader && authHeader === 'Bearer empresa-admin-session-token-abc123xyz') {
      next();
    } else {
      res.status(401).json({ error: 'Não autorizado. Faça login como administrador.' });
    }
  };

  // ==========================================
  // AUTH API
  // ==========================================
  app.post('/api/auth/login', (req, res) => {
    const { email, password } = req.body;
    if (email === 'admin@empresa.com' && password === 'admin123') {
      res.json({
        token: 'empresa-admin-session-token-abc123xyz',
        user: {
          name: 'Mariana Costa (Diretora de RH)',
          email: 'admin@empresa.com',
          role: 'Admin'
        }
      });
    } else {
      res.status(401).json({ error: 'E-mail ou senha incorretos.' });
    }
  });

  // ==========================================
  // STATS API
  // ==========================================
  app.get('/api/stats', requireAdmin, (req, res) => {
    try {
      const stats = db.getStats();
      res.json(stats);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  // ==========================================
  // VACANCIES API
  // ==========================================
  app.get('/api/vacancies', (req, res) => {
    try {
      const vacancies = db.getVacancies();
      res.json(vacancies);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.get('/api/vacancies/:id', (req, res) => {
    try {
      const vacancy = db.getVacancyById(req.params.id);
      if (vacancy) {
        res.json(vacancy);
      } else {
        res.status(404).json({ error: 'Vaga não encontrada.' });
      }
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.post('/api/vacancies', requireAdmin, (req, res) => {
    try {
      const { title, description, responsibilities, requirements, benefits, city, state, modality, salaryRange, slots } = req.body;
      const newVacancy: Vacancy = {
        id: `vaga-${Date.now()}`,
        title,
        description,
        responsibilities: Array.isArray(responsibilities) ? responsibilities : [],
        requirements: Array.isArray(requirements) ? requirements : [],
        benefits: Array.isArray(benefits) ? benefits : [],
        city,
        state,
        modality,
        salaryRange,
        slots: Number(slots) || 1,
        status: 'Ativa',
        createdAt: new Date().toISOString()
      };
      db.saveVacancy(newVacancy);
      res.status(201).json(newVacancy);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.put('/api/vacancies/:id', requireAdmin, (req, res) => {
    try {
      const existing = db.getVacancyById(req.params.id);
      if (!existing) {
        return res.status(404).json({ error: 'Vaga não encontrada.' });
      }
      const updatedVacancy: Vacancy = {
        ...existing,
        ...req.body,
        id: existing.id // protect ID
      };
      db.saveVacancy(updatedVacancy);
      res.json(updatedVacancy);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.delete('/api/vacancies/:id', requireAdmin, (req, res) => {
    try {
      const deleted = db.deleteVacancy(req.params.id);
      if (deleted) {
        res.json({ success: true, message: 'Vaga excluída com sucesso.' });
      } else {
        res.status(404).json({ error: 'Vaga não encontrada.' });
      }
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  // ==========================================
  // CANDIDATES API
  // ==========================================
  app.get('/api/candidates', requireAdmin, (req, res) => {
    try {
      const candidates = db.getCandidates();
      res.json(candidates);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.get('/api/candidates/:id', requireAdmin, (req, res) => {
    try {
      const candidate = db.getCandidateById(req.params.id);
      if (candidate) {
        res.json(candidate);
      } else {
        res.status(404).json({ error: 'Candidato não encontrado.' });
      }
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  // AI-powered Natural Language Search
  app.post('/api/candidates/search-ai', requireAdmin, async (req, res) => {
    try {
      const { query } = req.body;
      if (!query || typeof query !== 'string') {
        return res.status(400).json({ error: 'A consulta de busca por IA é obrigatória.' });
      }
      const candidates = db.getCandidates();
      const results = await searchCandidatesAi(candidates, query);
      res.json(results);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  // IA Resume Parsing (Auto-complete for candidates)
  app.post('/api/candidates/parse-resume', async (req, res) => {
    try {
      const { resumeText, resumeFileName, fileBase64, vacancyId } = req.body;
      let vacancy: Vacancy | undefined = undefined;
      if (vacancyId) {
        vacancy = db.getVacancyById(vacancyId);
      }

      const parsedData = await parseResumeAndScore(
        resumeText || '',
        resumeFileName || 'curriculo.pdf',
        vacancy,
        fileBase64 ? { data: fileBase64, mimeType: 'application/pdf' } : undefined
      );

      res.json(parsedData);
    } catch (e: any) {
      console.error('Erro no processamento do currículo por IA:', e);
      res.status(500).json({ error: 'Falha ao processar currículo por IA. Digite manualmente ou tente outro arquivo.' });
    }
  });

  // Candidate Apply (Public)
  app.post('/api/candidates/apply', async (req, res) => {
    try {
      const {
        vacancyId,
        submissionMode,
        name,
        email,
        phone,
        city,
        state,
        birthDate,
        education,
        desiredRole,
        salaryExpectation,
        availability,
        linkedin,
        portfolio,
        github,
        experiences,
        courses,
        skills,
        languages,
        coverLetter,
        resumeFileName,
        resumeText,
        fileBase64,
        aiScore,
        aiReason,
        aiSummary,
        aiInsights,
        tags
      } = req.body;

      const isPdfOnly = submissionMode === 'pdf_only';
      if (!name || !email || !phone || (!isPdfOnly && (!city || !state))) {
        return res.status(400).json({ error: 'Os campos Nome, E-mail e Telefone são obrigatórios.' });
      }

      // Check if candidate already applied to this specific vacancy to avoid duplicate spam
      if (vacancyId) {
        const existing = db.getCandidates().find(c => c.email === email && c.vacancyId === vacancyId);
        if (existing) {
          return res.status(400).json({ error: 'Você já se candidatou para esta vaga. Nosso time de recrutamento já está avaliando seu currículo!' });
        }
      }

      // 1. Physically save the PDF to the "curriculos" folder if provided
      let savedResumePath = '';
      if (fileBase64 && resumeFileName && submissionMode !== 'form_only') {
        try {
          const safeName = resumeFileName.replace(/[^a-zA-Z0-9.\-_]/g, '_');
          const fileId = `cand-${Date.now()}`;
          const fileNameOnDisk = `${fileId}_${safeName}`;
          const filePath = path.join(RESUMES_DIR, fileNameOnDisk);
          fs.writeFileSync(filePath, Buffer.from(fileBase64, 'base64'));
          savedResumePath = `/api/candidates/resume/download/${fileNameOnDisk}`;
        } catch (fileErr) {
          console.error('Erro ao gravar currículo em disco:', fileErr);
        }
      }

      const newCandidate: Candidate = {
        id: `cand-${Date.now()}`,
        vacancyId,
        submissionMode: submissionMode || (resumeFileName ? 'both' : 'form_only'),
        name,
        email,
        phone,
        city: city || '',
        state: state || '',
        birthDate: birthDate || '',
        education: education || 'Ensino Médio Completo',
        desiredRole: desiredRole || 'Candidatura Geral',
        salaryExpectation: String(salaryExpectation || ''),
        availability: availability || 'Imediata',
        linkedin: linkedin || '',
        portfolio: portfolio || '',
        github: github || '',
        experiences: Array.isArray(experiences) ? experiences : [],
        courses: Array.isArray(courses) ? courses : [],
        skills: Array.isArray(skills) ? skills : [],
        languages: Array.isArray(languages) ? languages : [],
        coverLetter: coverLetter || '',
        resumeFileName: resumeFileName || '',
        resumeText: resumeText || '',
        createdAt: new Date().toISOString(),
        status: 'Novo',
        favorite: false,
        stars: 0,
        tags: Array.isArray(tags) ? tags : [],
        notes: '',
        history: [
          {
            id: `log-${Date.now()}-init`,
            date: new Date().toISOString(),
            user: 'Sistema',
            action: 'Candidatura Recebida',
            details: isPdfOnly 
              ? 'O candidato enviou sua candidatura no modo Apenas PDF.' 
              : 'O candidato preencheu o formulário e enviou sua candidatura com sucesso.'
          }
        ],
        resumeUrl: savedResumePath || undefined,
        aiScore: aiScore ? Number(aiScore) : undefined,
        aiReason: aiReason || undefined,
        aiSummary: aiSummary || undefined,
        aiInsights: aiInsights || undefined
      };

      // 2. Perform AI evaluation
      if (isPdfOnly) {
        // For "Apenas PDF", we do NOT read/parse PDF files anymore.
        newCandidate.aiSummary = 'Candidato inscrito via Apenas PDF. O currículo físico está armazenado na pasta de currículos do servidor para avaliação manual.';
        newCandidate.tags = ['Apenas PDF', ...newCandidate.tags];
        newCandidate.aiScore = undefined;
        newCandidate.aiReason = undefined;
        newCandidate.aiInsights = undefined;
        newCandidate.history.push({
          id: `log-${Date.now()}-pdf-only`,
          date: new Date().toISOString(),
          user: 'Sistema',
          action: 'Triagem Pendente',
          details: 'Candidatura recebida no modo Apenas PDF. Faça a triagem e leitura manual abrindo o arquivo PDF anexo.'
        });
      } else {
        // For "Formulário" or "PDF + Formulário", we evaluate based solely on their structured form data
        const vacancy = vacancyId ? db.getVacancyById(vacancyId) : undefined;
        if (vacancy) {
          try {
            const experiencesText = newCandidate.experiences.map(exp => `- ${exp.role} na ${exp.company} (${exp.period}): ${exp.description}`).join('\n');
            const skillsText = newCandidate.skills.join(', ');
            const languagesText = newCandidate.languages.map(lang => `- ${lang.language} (${lang.level})`).join('\n');
            const coursesText = newCandidate.courses.join(', ');
            
            const profileText = `
CANDIDATO: ${newCandidate.name}
Cargo Pretendido: ${newCandidate.desiredRole}
Escolaridade: ${newCandidate.education}
Pretensão Salarial: ${newCandidate.salaryExpectation}
Disponibilidade: ${newCandidate.availability}

EXPERIÊNCIAS PROFISSIONAIS:
${experiencesText || 'Nenhuma informada'}

COMPETÊNCIAS / SKILLS:
${skillsText || 'Nenhuma informada'}

IDIOMAS:
${languagesText || 'Nenhum informado'}

CURSOS & CERTIFICAÇÕES:
${coursesText || 'Nenhum informado'}

CARTA DE APRESENTAÇÃO:
${newCandidate.coverLetter || 'Nenhuma informada'}
`;

            const aiData = await parseResumeAndScore(
              profileText,
              newCandidate.resumeFileName || 'formulario.pdf',
              vacancy
              // Do NOT pass fileBase64, skipping PDF reading entirely as requested
            );

            newCandidate.aiScore = aiData.aiScore;
            newCandidate.aiReason = aiData.aiReason;
            newCandidate.aiSummary = aiData.aiSummary;
            newCandidate.aiInsights = aiData.aiInsights;
            newCandidate.tags = [...new Set([...(newCandidate.tags || []), ...(aiData.tags || [])])];
            newCandidate.history.push({
              id: `log-${Date.now()}-ai-retro`,
              date: new Date().toISOString(),
              user: 'Sistema IA',
              action: 'Análise de Formulário',
              details: `Dados do formulário avaliados automaticamente pela IA. Compatibilidade de ${aiData.aiScore}% detectada.`
            });
          } catch (err) {
            console.error('Erro na análise de IA baseada no formulário:', err);
          }
        } else {
          // No specific vacancy selected
          newCandidate.aiScore = undefined;
          newCandidate.aiReason = undefined;
          newCandidate.aiInsights = undefined;
          newCandidate.aiSummary = 'Candidato inscrito via Candidatura Espontânea. Seus dados estão salvos e ele poderá ser associado a vagas futuramente para obter a análise inteligente.';
        }
      }

      db.saveCandidate(newCandidate);
      res.status(201).json(newCandidate);
    } catch (e: any) {
      console.error(e);
      res.status(500).json({ error: e.message });
    }
  });

  // Admin update candidate (status, tags, notes, star, favorite)
  app.put('/api/candidates/:id', requireAdmin, (req, res) => {
    try {
      const existing = db.getCandidateById(req.params.id);
      if (!existing) {
        return res.status(404).json({ error: 'Candidato não encontrado.' });
      }

      // Check changes for History Logs
      const historyLogs = [...(existing.history || [])];
      const updater = 'Mariana Costa (RH)';

      if (req.body.status && req.body.status !== existing.status) {
        historyLogs.push({
          id: `log-edit-${Date.now()}-status`,
          date: new Date().toISOString(),
          user: updater,
          action: 'Alteração de Status',
          details: `Status alterado de "${existing.status}" para "${req.body.status}".`
        });
      }

      if (req.body.favorite !== undefined && req.body.favorite !== existing.favorite) {
        historyLogs.push({
          id: `log-edit-${Date.now()}-fav`,
          date: new Date().toISOString(),
          user: updater,
          action: req.body.favorite ? 'Marcado como Favorito' : 'Removido dos Favoritos',
          details: req.body.favorite ? 'Candidato adicionado à lista de favoritos corporativos.' : 'Candidato removido dos favoritos.'
        });
      }

      if (req.body.stars !== undefined && req.body.stars !== existing.stars) {
        historyLogs.push({
          id: `log-edit-${Date.now()}-stars`,
          date: new Date().toISOString(),
          user: updater,
          action: 'Classificação por Estrelas',
          details: `Classificação atualizada para ${req.body.stars} estrelas.`
        });
      }

      if (req.body.notes !== undefined && req.body.notes !== existing.notes) {
        historyLogs.push({
          id: `log-edit-${Date.now()}-notes`,
          date: new Date().toISOString(),
          user: updater,
          action: 'Observação Atualizada',
          details: 'Anotações administrativas privadas foram editadas.'
        });
      }

      const updatedCandidate: Candidate = {
        ...existing,
        ...req.body,
        history: historyLogs,
        id: existing.id // protect ID
      };

      db.saveCandidate(updatedCandidate);
      res.json(updatedCandidate);
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  app.delete('/api/candidates/:id', requireAdmin, (req, res) => {
    try {
      const deleted = db.deleteCandidate(req.params.id);
      if (deleted) {
        res.json({ success: true, message: 'Candidato excluído com sucesso.' });
      } else {
        res.status(404).json({ error: 'Candidato não encontrado.' });
      }
    } catch (e: any) {
      res.status(500).json({ error: e.message });
    }
  });

  // Download/View Candidate PDF Resume
  app.get('/api/candidates/resume/download/:filename', (req, res) => {
    try {
      const filename = req.params.filename;
      // Prevent directory traversal
      const safeFilename = path.basename(filename);
      const filePath = path.join(RESUMES_DIR, safeFilename);

      if (!fs.existsSync(filePath)) {
        return res.status(404).json({ error: 'Currículo não encontrado.' });
      }

      res.setHeader('Content-Type', 'application/pdf');
      res.setHeader('Content-Disposition', `inline; filename="${safeFilename.substring(safeFilename.indexOf('_') + 1)}"`);
      res.sendFile(filePath);
    } catch (e: any) {
      res.status(500).json({ error: 'Erro ao abrir o currículo.' });
    }
  });

  // Export Candidates to Excel (CSV format, fully compatible with Excel)
  app.get('/api/export/csv', requireAdmin, (req, res) => {
    try {
      const candidates = db.getCandidates();
      
      // UTF-8 BOM to make sure Excel opens accented Portuguese characters perfectly
      let csvContent = '\uFEFF';
      
      // Headers
      const headers = [
        'ID', 'Nome', 'E-mail', 'Telefone', 'Cidade', 'Estado', 'Vaga Vinculada', 
        'Cargo Desejado', 'Escolaridade', 'Pretensão Salarial', 'Disponibilidade', 
        'Status', 'Favorito', 'Estrelas (0-5)', 'Score de IA (%)', 'Tags', 'Data de Cadastro'
      ];
      
      csvContent += headers.map(h => `"${h.replace(/"/g, '""')}"`).join(';') + '\n';
      
      candidates.forEach(c => {
        const row = [
          c.id,
          c.name,
          c.email,
          c.phone,
          c.city,
          c.state,
          c.vacancyTitle || 'Candidatura Geral',
          c.desiredRole,
          c.education,
          c.salaryExpectation,
          c.availability,
          c.status,
          c.favorite ? 'Sim' : 'Não',
          c.stars,
          c.aiScore !== undefined ? `${c.aiScore}%` : 'N/A',
          c.tags.join(', '),
          new Date(c.createdAt).toLocaleDateString('pt-BR')
        ];
        csvContent += row.map(val => `"${String(val || '').replace(/"/g, '""')}"`).join(';') + '\n';
      });

      res.setHeader('Content-Type', 'text/csv; charset=utf-8');
      res.setHeader('Content-Disposition', 'attachment; filename=candidatos_recrutamento.csv');
      res.status(200).send(csvContent);
    } catch (e: any) {
      res.status(500).json({ error: 'Erro ao exportar arquivo.' });
    }
  });

  // ==========================================
  // DEV SERVER & STATIC ASSETS
  // ==========================================
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`[Servidor Recrutamento] Rodando em http://localhost:${PORT}`);
  });
}

startServer();
